sql:
SELECT state_id, graduation_rate
FROM high_school_graduation
WHERE year_recorded = (SELECT MAX(year_recorded) FROM high_school_graduation);

SELECT murder_rate, number_of_incidents
FROM murder_rates
WHERE year_recorded = 2020;

SELECT state_name 
FROM states 
ORDER BY state_name;

external_knowledge:
- High school graduation rates are a measure of the number of students who graduate from high school within four years of starting ninth grade, expressed as a percentage;
- Poverty rates are the percentages of the population living in households with incomes below the poverty threshold;
- Single-parent household rates refer to the percentage of households with children under the age of 18 headed by a single parent;
- Median income is the middle value of household income in an area, where half the households have higher incomes and half have lower incomes.

